sys_script_include.script:
var ZipUtil = Class.create();
ZipUtil.prototype = (function() {
    var DEFAULT_ENCODING = 'ISO8859_1';
    //var GlobalZipUtils = new global.ExtranetGlobalUtils();
    var CRCUtil = new DocxUtil();
    var crc32 = function(str) {
        return CRCUtil.crc32(str);
    };

    /**
     * Convert an array of numbers into an array of characters
     * @param {array} numbers 
     */
    function bin2String(numbers) {
        return String.fromCharCode.apply(String, numbers);
    }

    /**
     * Convert an array of numbers into an array of characters into a byte[]
     * @param {array} numbers 
     */
    function numberArrayToBytes(numbers, encoding) {
        encoding = encoding || DEFAULT_ENCODING;
        return Packages.java.lang.String(bin2String(numbers)).getBytes(encoding);
    }

    function getStringBytes(string, encoding) {
        encoding = encoding || DEFAULT_ENCODING;
        return Packages.java.lang.String(string).getBytes(encoding);
    }

    /**
     * Convert a java byte[] into a JS number array
     * @param {byte[]} bytes 
     */
    function bytesToNumberArray(bytes) {
        var array = new Array(bytes.length);
        for (var i = 0; i < bytes.length; i++)
            array[i] = bytes[i];
        return array;
    }

    /**
     * Write an array of numbers to an attachment as bytes
     * @param {*} fileName 
     * @param {*} contentType 
     * @param {*} bytes_as_numbers 
     * @param {*} table 
     * @param {*} sys_id 
     */
    function createAttachmentFromBytes(fileName, contentType, bytes_as_numbers, table, sys_id, encoding) {
        var attachmentRecord = new GlideRecord(table);
        attachmentRecord.get(sys_id);

        var sa = new GlideSysAttachment();
        var sysIdNewAttachment = sa.write(attachmentRecord, fileName, contentType, numberArrayToBytes(bytes_as_numbers, encoding));

        return sysIdNewAttachment;
    }

    /**
     * Fetch the raw byte data of an attachment record as an array of numbers
     * @param {*} attachment_record 
     */
    function getAttachmentBytes(attachment_record) {
        return bytesToNumberArray(new GlideSysAttachment().getBytes(attachment_record));
    }

    // Flip endianness
    function swap16(val) {
        return ((val & 0xFF) << 8) |
            ((val >> 8) & 0xFF);
    }

    function swap32(val) {
        return ((val & 0xFF) << 24) |
            ((val & 0xFF00) << 8) |
            ((val >> 8) & 0xFF00) |
            ((val >> 24) & 0xFF);
    }

    /**
     * Build a string from an array of characters
     * @param {array} arr 
     */
    function charArrayToString(arr) {
        var chars = new Array(arr.length);
        for (var i = 0; i < arr.length; i++) {
            chars[i] = String.fromCharCode(arr[i] & 0xFF);
        }
        return chars.join("");
    }

    /**
     * Build an array of characters from a string
     * @param {string} str 
     */
    function stringToCharArray(str) {
        var arr = str.split('');
        return arr.map(
            function(c) {
                return c.charCodeAt(0);
            }
        );
    }

    /**
     * Test a bitflag for a set flag
     * @param {number} bits 
     * @param {number} flag 
     */
    function checkFlag(bits, flag) {
        return (bits & flag) == flag;
    }

    /**
     * Combine a low and high byte into a little endian word
     * @param {number} lo 
     * @param {number} hi 
     */
    function toWord(lo, hi) {
        return (hi << 8 | lo) >>> 0;
    }

    /**
     * Combine a 4-length array of bytes into a little endian dword
     * @param {array} bytes 
     */
    function toDWord(bytes) {
        return (bytes[0] | (bytes[1] << 8) | (bytes[2] << 16) | (bytes[3] << 24)) >>> 0;
    }

    /**
     * Create an instance of a ByteWriter
     * ByteWriters progressively build an array of bytes
     * @param {number} length 
     */
    function ByteWriter(length) {
        length = length | 0;
        var offset = 0;
        var bytes = new Array(length);

        this.writeBytes = function(bytesarray) {
            for (var i = 0; i < bytesarray.length; i++)
                bytes[offset++] = 0xFF & bytesarray[i];
            return this;
        };

        this.writeBytesRaw = function(bytesarray) {
            for (var i = 0; i < bytesarray.length; i++)
                bytes[offset++] = bytesarray[i];
            return this;
        };

        this.setPosition = function(pos) {
            return offset = pos;
        };

        this.getPosition = function() {
            return offset;
        };

        this.skip = function(len) {
            offset += len;
            return this;
        };

        this.writeWord = function(value) {
            this.writeBytes([
                value & 0x00FF,
                (value & 0xFF00) >> 8
            ]);
            return this;
        };

        this.writeDWord = function(value) {
            this.writeBytes([
                value & 0x000000FF,
                (value & 0x0000FF00) >> 8,
                (value & 0x00FF0000) >> 16,
                (value & 0xFF000000) >> 24
            ]);
            return this;
        };

        this.getBytes = function() {
            return bytes;
        };

    }

    /**
     * Create an instance of a ByteReader
     * ByteReaders progressively consume an array of bytes
     * @param {number} length 
     */
    function ByteReader(bytes) {
        var offset = 0;
        this.readBytes = function(len) {
            len = len || 0;
            var buf = [];
            while (len-- > 0) {
                buf.push((0xFF & bytes[offset++]) >>> 0);
            }
            return buf;
        };

        this.readBytesRaw = function(len) {
            len = len || 0;
            var buf = [];
            while (len-- > 0) {
                buf.push(bytes[offset++]);
            }
            return buf;
        };

        this.hasBytes = function() {
            return offset < bytes.length;
        };

        this.skip = function(len) {
            offset += len;
        };

        this.readDWord = function() {
            return toDWord(this.readBytes(4));
        };

        this.readWord = function() {
            var bytes = this.readBytes(2);
            return toWord(bytes[0], bytes[1]);
        };
    }

    /** END OF CENTRAL DIRECTORY STRUCTURE */

    /**
    	OFFSET              Count TYPE   Description
    	0000h                   4 char   ID='PK',05,06
    	0004h                   1 word   Number of this disk
    	0006h                   1 word   Number of disk with start of central directory
    	0008h                   1 word   Total number of file/path entries on this disk
    	000Ah                   1 word   Total number of entries in central dir
    	000Ch                   1 dword  Size of central directory
    	0010h                   1 dword  Offset of start of central directory relative
    									to starting disk number
    	0014h                   1 word   Archive comment length
    									="CML"
    	0016h               "CML" char   Zip file comment
    */

    function readEndOfCentralDirectoryStructure(reader) {
        var out = {};
        out.disk_number = reader.readWord();
        out.first_disk_number = reader.readWord();
        out.num_files_on_disk = reader.readWord();
        out.num_central_dir_entries = reader.readWord();
        out.central_dir_size = reader.readDWord();
        out.central_dir_rel_offset = reader.readDWord();
        var comment_length = reader.readWord();
        out.file_comment = charArrayToString(reader.readBytes(comment_length));
        return out;
    }

    function writeEndOfCentralDirectoryStructure(writer, eocds, cds_offset, cds_size) {
        writer.writeDWord(0x06054b50);
        writer.writeWord(eocds.disk_number);
        writer.writeWord(eocds.first_disk_number);
        writer.writeWord(eocds.num_files_on_disk);
        writer.writeWord(eocds.num_central_dir_entries);
        writer.writeDWord(cds_size);
        writer.writeDWord(cds_offset);
        writer.writeWord(eocds.file_comment.length);
        writer.writeBytes(stringToCharArray(eocds.file_comment));
    }

    /** END END CENTRAL DIRECTORY STRUCTURE */

    /** CENTRAL DIRECTORY STRUCTURE */

    /**
    	OFFSET              Count TYPE   Description
    	0000h                   4 char   ID='PK',01,02
    	0004h                   1 byte   Version made by
    	0005h                   1 byte   Host OS (see table 0011)
    	0006h                   1 byte   Minimum version needed to extract
    	0007h                   1 byte   Target OS
    									see above "Host OS"
    	0008h                   1 word   General purpose bit flag
    									see above "General purpose bit flag"
    	000Ah                   1 word   Compression method
    									see above "Compression method"
    	000Ch                   1 dword  DOS date / time of file
    	0010h                   1 dword  32-bit CRC of file (see table 0009)
    	0014h                   1 dword  Compressed size of file
    	0018h                   1 dword  Uncompressed size of file
    	001Ch                   1 word   Length of filename
    									="LEN"
    	001Eh                   1 word   Length of extra field
    									="XLN"
    	0020h                   1 word   Length of file comment
    									="CMT"
    	0022h                   1 word   Disk number ??
    	0024h                   1 word   Internal file attributes (bit mapped)
    										0 - file is apparently an ASCII/binary file
    									1-15 - unused
    	0026h                   1 dword  External file attributes (OS dependent)
    	002Ah                   1 dword  Relative offset of local header from the
    									start of the first disk this file appears on
    	002Eh               "LEN" char   Filename / path; should not contain a drive
    									or device letter, all slashes should be forward
    									slashes '/'.
    	002Eh+              "XLN" char   Extra field
    	+"LEN"
    	002Eh               "CMT" char   File comment
    	+"LEN"
    	+"XLN"

    	(Table 0011)
    	PkZip Host OS table
    	0 - MS-DOS and OS/2 (FAT)
    	1 - Amiga
    	2 - VMS
    	3 - *nix
    	4 - VM/CMS
    	5 - Atari ST
    	6 - OS/2 1.2 extended file sys
    	7 - Macintosh
    	8-255 - unused
    */

    function readCentralDirectoryStructure(reader) {

        var out = {};
        var buf = reader.readBytes(4);
        out.version_made_by = buf[0];
        out.host_os = buf[1];
        out.min_version_needed = buf[2];
        out.target_os = buf[3];

        out.bitfield = reader.readWord();
        out.compression_method = reader.readWord();

        out.dos_date = reader.readDWord();
        out.crc32 = reader.readDWord();
        out.compressed_size = reader.readDWord();
        out.uncompressed_size = reader.readDWord();

        var filename_length = reader.readWord();
        var extrafield_length = reader.readWord();
        var filecomment_length = reader.readWord();

        out.disk_number = reader.readWord();
        out.file_attribs = reader.readWord();

        out.ext_file_attribs = reader.readDWord();
        out.rel_offset = reader.readDWord();
        out.file_name = charArrayToString(reader.readBytes(filename_length));
        out.extra_field = reader.readBytes(extrafield_length);
        out.file_comment = charArrayToString(reader.readBytes(filecomment_length));

        return out;
    }


    function writeCentralDirectoryStructure(writer, cds, file) {
        writer.writeDWord(0x02014b50);
        writer.writeBytes([
            cds.version_made_by,
            cds.host_os,
            cds.min_version_needed,
            cds.target_os
        ]);

        writer.writeWord(cds.bitfield);
        writer.writeWord(cds.compression_method);

        writer.writeDWord(cds.dos_date);
        writer.writeDWord(file.crc32);
        writer.writeDWord(file.compressed_size);
        writer.writeDWord(file.uncompressed_size);

        writer.writeWord(cds.file_name.length);
        writer.writeWord(cds.extra_field.length);
        writer.writeWord(cds.file_comment.length);

        writer.writeWord(cds.disk_number);
        writer.writeWord(cds.file_attribs);

        writer.writeDWord(cds.ext_file_attribs);
        writer.writeDWord(file.local_offset);
        writer.writeBytes(stringToCharArray(cds.file_name));
        writer.writeBytes(cds.extra_field);
        writer.writeBytes(stringToCharArray(cds.file_comment));
    }

    /** END CENTRAL DIRECTORY STRUCTURE */


    /** FILE ENTRIES */

    /**
    	OFFSET              Count TYPE   Description
    	0000h                   4 char   ID='PK',03,04
    	0004h                   1 word   Version needed to extract archive
    	0006h                   1 word   General purpose bit field (bit mapped)
    										0 - file is encrypted
    										1 - 8K/4K sliding dictionary used
    										2 - 3/2 Shannon-Fano trees were used
    										3-4 - unused
    									5-15 - used internally by ZIP
    									Note:  Bits 1 and 2 are undefined if the
    											compression method is other than
    											type 6 (Imploding).
    	0008h                   1 word   Compression method (see table 0010)
    	000Ah                   1 dword  Original DOS file date/time (see table 0009)
    	000Eh                   1 dword  32-bit CRC of file (inverse??)
    	0012h                   1 dword  Compressed file size
    	0016h                   1 dword  Uncompressed file size
    	001Ah                   1 word   Length of filename
    									="LEN"
    	001Ch                   1 word   Length of extra field
    									="XLN"
    	001Eh               "LEN" char   path/filename
    	001Eh               "XLN" char   extra field
    	+"LEN"
    	After all the files, there comes the central directory structure.
    	(Table 0010)
    	PkZip compression types
    	0 - Stored / No compression
    	1 - Shrunk / LZW, 8K buffer, 9-13 bits with partial clearing
    	2 - Reduced-1 / Probalistic compression, lower 7 bits
    	3 - Reduced-2 / Probalistic compression, lower 6 bits
    	4 - Reduced-3 / Probalistic compression, lower 5 bits
    	5 - Reduced-4 / Probalistic compression, lower 4 bits
    	6 - Imploded / 2/3 Shanno-Fano trees, 4K/8K sliding dictionary
    */

    function writeFileEntry(writer, file) {
        file.local_offset = writer.getPosition();
        writer.writeDWord(0x04034b50);
        writer.writeWord(file.version);
        writer.writeWord(file.bitfield);
        writer.writeWord(file.compression_method);

        writer.writeDWord(file.dos_time);
        writer.writeDWord(file.crc32);

        writer.writeDWord(file.compressed_size);
        writer.writeDWord(file.uncompressed_size);

        writer.writeWord(file.file_name.length);
        writer.writeWord(file.extra_field.length);
        writer.writeBytes(stringToCharArray(file.file_name));
        writer.writeBytes(file.extra_field);
        writer.writeBytes(file.file_data);
    }

    function readFileEntry(reader) {
        var out = {};

        out.version = reader.readWord();
        out.bitfield = reader.readWord();
        out.compression_method = reader.readWord();

        out.dos_time = reader.readDWord();
        out.crc32 = reader.readDWord();

        out.compressed_size = reader.readDWord();
        out.uncompressed_size = reader.readDWord();

        var name_length = reader.readWord();
        var extra_field_length = reader.readWord();
        out.file_name = charArrayToString(reader.readBytes(name_length));
        out.extra_field = reader.readBytes(extra_field_length);

        if (out.bitfield == 2056 && (gs.nil(out.compressed_size) || out.compressed_size == 0)) {
            var rawData = [];
            while (reader.hasBytes()) {
                rawData.push(reader.readBytes(1)[0]);
                var l = rawData.length;
                var d = charArrayToString([rawData[l - 4], rawData[l - 3]]) + "," + rawData[l - 2] + "," + rawData[l - 1];
                if (l > 3 && d == "PK,7,8") {
                    rawData.slice(l - 1);
                    rawData.slice(l - 2);
                    rawData.slice(l - 3);
                    rawData.slice(l - 4);

                    out.file_data = rawData;
                    break;
                }
            }
            out.crc32 = reader.readDWord();
            out.compressed_size = reader.readDWord();
            out.uncompressed_size = reader.readDWord();
        } else {
            out.file_data = reader.readBytes(out.compressed_size);
        }

        //gs.info("readFileEntry: " + JSON.stringify(out,null,"\t"));
        return out;
    }

    /** END FILE ENTRIES */


    /**
     * Read a ZIP archive from an array of pkzip compatible bytes
     * @param {array} bytes 
     */
    function bytesToZipStructure(bytes) {
        var output = {
            ziputil_version: "1",
            files: [],
            central_directory: [],
            end_of_central_directory: {}
        };
        var reader = new ByteReader(bytes);
        while (reader.hasBytes()) {
            var ID = charArrayToString(reader.readBytes(2)) + ',' + reader.readBytes(1) + ',' + reader.readBytes(1);
            switch (ID) {
                case 'PK,3,4':
                    output.files.push(readFileEntry(reader));
                    break;
                case 'PK,1,2':
                    output.central_directory.push(readCentralDirectoryStructure(reader));
                    break;
                case 'PK,5,6':
                    output.end_of_central_directory = readEndOfCentralDirectoryStructure(reader);
                    break;
                default:
                    throw "Unknown zip block ID: " + ID;
            }
        }
        //TODO: We may need to use CDS crc32s in place of the file entry data
        return output;
    }

    /**
     * Get a zip structure as an array of pkzip compatible bytes
     * @param {*} zip_struct 
     */
    function zipStructureToBytes(zip_struct) {
        var writer = new ByteWriter();
        var i;

        // files. Keep tally of directory structure
        for (i = 0; i < zip_struct.files.length; i++) {
            var file = zip_struct.files[i];
            writeFileEntry(writer, file);
        }

        var beginning_of_cds = writer.getPosition();
        // central directory 
        for (i = 0; i < zip_struct.central_directory.length; i++) {
            var cds = zip_struct.central_directory[i];
            writeCentralDirectoryStructure(writer, cds, zip_struct.files[i]);
        }
        var size_of_cds = writer.getPosition() - beginning_of_cds;

        // end of central directory 
        writeEndOfCentralDirectoryStructure(writer, zip_struct.end_of_central_directory, beginning_of_cds, size_of_cds);

        return writer.getBytes();

    }

    /**
     * Compress every file in a zip structure
     * @param {*} zip_struct 
     */
    function compress(zip_struct) {
        zip_struct = JSON.parse(JSON.stringify(zip_struct));
        var deflater = new ZipDeflater();
        zip_struct.files = zip_struct.files.map(function(file) {
            file.uncompressed_size = file.file_data.length;
            file.crc32 = crc32(charArrayToString(file.file_data));
            if (file.compression_method == '8')
                file.file_data = deflater.pako.deflateRaw(file.file_data);
            file.compressed_size = file.file_data.length;
            return file;
        });
        return zip_struct;
    }

    /**
     * Decompress every file in a zip structure
     * @param {*} zip_struct 
     */
    function decompress(zip_struct) {
        zip_struct = JSON.parse(JSON.stringify(zip_struct));
        var inflater = new ZipInflater();
        zip_struct.files = zip_struct.files.map(function(file) {
            if (file.compression_method == '8')
                file.file_data = inflater.pako.inflateRaw(file.file_data);
            return file;
        });
        return zip_struct;
    }

    /**
     * Create an array/object/string representation of the contents of a zipped attachment
     * @param {*} attachment_id 
     */
    function unzip(attachment_id) {
        var attachment_record = new GlideRecord('sys_attachment');
        if (attachment_record.get(attachment_id)) {
            var bytes = getAttachmentBytes(attachment_record);
            return decompress(bytesToZipStructure(bytes));
        }
        return null;
    }

    function rezip_v1(zip_struct) {
        return zipStructureToBytes(compress(zip_struct));
    }

    function rezipAsBytes(zip_structure) {
        var bytes;
        switch (zip_structure.ziputil_version) {
            case '1':
                bytes = rezip_v1(zip_structure);
                break;
            default:
                throw 'Incompatible version ' + zip_structure.ziputil_version;
        }
        if (bytes) {
            return bytes;
        }
        return null;
    }

    /**
     * Combine zip structure to form a new binary attachment and return its sys_id
     * @param {*} zip_structure // The structure from which to create an attachment
     * @param {*} target_table  // The target table for the attachment
     * @param {*} target_record // The target record for the attachment
     */
    function rezip(zip_structure, file_name, target_table, target_record, mime_type) {
        var bytes;
        switch (zip_structure.ziputil_version) {
            case '1':
                bytes = rezip_v1(zip_structure);
                break;
            default:
                throw 'Incompatible version ' + zip_structure.ziputil_version;
        }
        if (bytes) {
            var sys_id = createAttachmentFromBytes(file_name, mime_type || '', bytes, target_table, target_record);
            return sys_id;
        }
        return null;
    }

    return {
        initialize: function() {},
        rezipAsBytes: rezipAsBytes,
        unzip: unzip,
        rezip: rezip,
        stringToCharArray: stringToCharArray,
        charArrayToString: charArrayToString,

        type: 'ZipUtil'
    };
})();
